// Enmascarar datos sensibles de Antonio
const sensitiveData = {
  'Antonio': '[AUTONOMO]',
  'NIF_ANTONIO': '[NIF_MASKED]',
  'DIRECCION_ANTONIO': '[DIRECCION_MASKED]',
  'TELEFONO_ANTONIO': '[TELEFONO_MASKED]',
  'EMAIL_ANTONIO': '[EMAIL_MASKED]'
};

// Obtener el texto procesado por Mistral
let processedText = $input.first().json.choices[0].message.content;

// Aplicar enmascaramiento
for (const [original, masked] of Object.entries(sensitiveData)) {
  const regex = new RegExp(original, 'gi');
  processedText = processedText.replace(regex, masked);
}

// Parsear el JSON si es posible
try {
  const parsedData = JSON.parse(processedText);
  return {
    json: {
      masked_data: parsedData,
      original_masked: true,
      processing_timestamp: new Date().toISOString()
    }
  };
} catch (error) {
  return {
    json: {
      masked_text: processedText,
      original_masked: true,
      processing_timestamp: new Date().toISOString(),
      parse_error: error.message
    }
  };
}

